/// Process source code and extract file intelligence using the global registry.
///
/// Parses the source with tree-sitter and extracts metrics, structure, imports,
/// exports, comments, docstrings, symbols, diagnostics, and/or chunks based on
/// the flags set in [`ProcessConfig`].
///
/// # Errors
///
/// Returns an error if the language is not found or parsing fails.
///
/// # Example
///
/// ```no_run
/// use tree_sitter_language_pack::{ProcessConfig, process};
///
/// let config = ProcessConfig::new("python").all();
/// let result = process("def hello(): pass", &config).unwrap();
/// println!("Language: {}", result.language);
/// println!("Lines: {}", result.metrics.total_lines);
/// println!("Structures: {}", result.structure.len());
/// ```
#[rustler::nif]
pub fn process(source: String, config: Option<String>) -> Result<ProcessResult, String> {
    let config_core: Option<tree_sitter_language_pack::ProcessConfig> = config
        .map(|s| serde_json::from_str::<tree_sitter_language_pack::ProcessConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let result = tree_sitter_language_pack::process(&source, config_core.as_ref().unwrap_or(&Default::default()))
        .map_err(|e| e.to_string())?;
    Ok(result.into())
}

/// Initialize the language pack with the given configuration.
///
/// Applies any custom cache directory, then downloads all languages and groups
/// specified in the config. This is the recommended entry point when you want
/// to pre-warm the cache before use.
///
/// # Errors
///
/// Returns an error if configuration cannot be applied or if downloads fail.
///
/// # Example
///
/// ```no_run
/// use tree_sitter_language_pack::{PackConfig, init};
///
/// let config = PackConfig {
///     cache_dir: None,
///     languages: Some(vec!["python".to_string(), "rust".to_string()]),
///     groups: None,
/// };
/// init(&config).unwrap();
/// ```
#[rustler::nif]
pub fn init(config: Option<String>) -> Result<(), String> {
    let config_core: Option<tree_sitter_language_pack::PackConfig> = config
        .map(|s| serde_json::from_str::<tree_sitter_language_pack::PackConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let result = tree_sitter_language_pack::init(config_core.as_ref().unwrap_or(&Default::default()))
        .map_err(|e| e.to_string())?;
    Ok(result)
}

/// Apply download configuration without downloading anything.
///
/// Use this to set a custom cache directory before the first call to
/// [`get_language`] or any download function. Changing the cache dir
/// after languages have been registered has no effect on already-loaded
/// languages.
///
/// # Errors
///
/// Returns an error if the lock cannot be acquired.
///
/// # Example
///
/// ```no_run
/// use std::path::PathBuf;
/// use tree_sitter_language_pack::{PackConfig, configure};
///
/// let config = PackConfig {
///     cache_dir: Some(PathBuf::from("/tmp/my-parsers")),
///     languages: None,
///     groups: None,
/// };
/// configure(&config).unwrap();
/// ```
#[rustler::nif]
pub fn configure(config: Option<String>) -> Result<(), String> {
    let config_core: Option<tree_sitter_language_pack::PackConfig> = config
        .map(|s| serde_json::from_str::<tree_sitter_language_pack::PackConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let result = tree_sitter_language_pack::configure(config_core.as_ref().unwrap_or(&Default::default()))
        .map_err(|e| e.to_string())?;
    Ok(result)
}

/// Download specific languages to the local cache.
///
/// Returns the number of requested languages available after the call. Already
/// compiled or cached languages are included in the count.
///
/// # Errors
///
/// Returns an error if any language is not available in the manifest or if
/// the download fails.
///
/// # Example
///
/// ```no_run
/// use tree_sitter_language_pack::download;
///
/// let count = download(&["python", "rust", "typescript"]).unwrap();
/// println!("Ensured {} languages", count);
/// ```
#[rustler::nif]
pub fn download(names: Vec<String>) -> Result<usize, String> {
    let names_refs: Vec<&str> = names.iter().map(|s| s.as_str()).collect();
    let result = tree_sitter_language_pack::download(&names_refs).map_err(|e| e.to_string())?;
    Ok(result)
}

/// Download all available languages from the remote manifest.
///
/// Downloads the platform bundle and extracts every library it contains.
/// Languages that appear in the manifest but are absent from the bundle
/// (e.g. grammars that failed to compile at release time) are silently
/// skipped — they are not treated as an error.
///
/// Returns the total number of languages now available (statically compiled
/// plus downloaded and cached).
///
/// # Errors
///
/// Returns an error if the manifest cannot be fetched or the bundle download fails.
///
/// # Example
///
/// ```no_run
/// use tree_sitter_language_pack::download_all;
///
/// let count = download_all().unwrap();
/// println!("{} languages available", count);
/// ```
#[rustler::nif]
pub fn download_all() -> Result<usize, String> {
    let result = tree_sitter_language_pack::download_all().map_err(|e| e.to_string())?;
    Ok(result)
}

